##template properties
name =Easy_Fabric_IPFM;
description = Fabric for a fully automated deployment of IP Fabric for Media Network with Nexus 9000 switches.;
tags =IPFM;
userDefined = false;
supportedPlatforms = All;
templateType = FABRIC;
templateSubType = NA;
contentType = PYTHON;
implements =implements;
dependencies = ;
published = false;
imports = ;
##
##template variables

#    Copyright (c) 2021-2023 by Cisco Systems, Inc.
#    All rights reserved.
#General
@(IsMandatory=true, IsFabricName=true, DisplayName="Fabric Name", Description="Name of the fabric (Max Size 64)")
string FABRIC_NAME{
  minLength = 1;
  maxLength = 64;
};

@(IsMandatory=true, ReadOnly=true, Enum="p2p", DisplayName="Fabric Interface Numbering", Description="Only Numbered(Point-to-Point) is supported")
string FABRIC_INTERFACE_TYPE
{
defaultValue=p2p;
};

@(IsMandatory=true, Enum="30,31", Description="Mask for Fabric Subnet IP Range", DisplayName="Fabric Subnet IP Mask")
integer SUBNET_TARGET_MASK
{
min = 30;
max = 31;
defaultValue=30;
};

@(IsMandatory=true, Enum="ospf,is-is", DisplayName="Fabric Routing Protocol", Description="Used for Spine-Leaf Connectivity")
string LINK_STATE_ROUTING
{
defaultValue=ospf;
};

@(IsMandatory=true, DisplayName="Fabric Routing Loopback Id", Description="(Min:0, Max:1023)")
integer ROUTING_LB_ID{
min=0;
max=1023;
defaultValue=0;
};

@(IsMandatory=true, DisplayName="Manual Fabric IP Address Allocation", Description="Checking this will disable Dynamic Fabric IP Address Allocations")
boolean STATIC_UNDERLAY_IP_ALLOC
{
defaultValue=false;
};

@(IsMandatory=true, IsShow="STATIC_UNDERLAY_IP_ALLOC==false", DisplayName="Fabric Routing Loopback IP Range", Description="Routing Loopback IP Address Range")
ipV4AddressWithSubnet LOOPBACK0_IP_RANGE
{
defaultValue=10.2.0.0/22;
};

@(IsMandatory=true, IsShow="STATIC_UNDERLAY_IP_ALLOC==false", DisplayName="Fabric Subnet IP Range", Description="Address range to assign Numbered IPs")
ipV4AddressWithSubnet SUBNET_RANGE
{
defaultValue=10.4.0.0/16;
};

@(IsMandatory=false, NoConfigChg=true, DisplayName="Enable Performance Monitoring")
boolean PM_ENABLE
{
defaultValue=false;
};

@(IsMandatory=false, IsInternal=true)
boolean PM_ENABLE_PREV
{
defaultValue=false;
};

#Multicast 

@(IsMandatory=true, DisplayName="Enable NBM Passive Mode", Description="Enable NBM mode to pim-passive for default VRF", Section="Multicast")
boolean ENABLE_NBM_PASSIVE
{
defaultValue=false;
};

@(IsMandatory=false, IsInternal=true)
boolean ENABLE_NBM_PASSIVE_PREV
{
defaultValue=false;
};

@(IsMandatory=true, IsShow="ENABLE_NBM_PASSIVE==false", DisplayName="Enable ASM", Description="Enable groups with receivers sending (*,G) joins", Section="Multicast")
boolean ENABLE_ASM
{
defaultValue=false;
};

@(IsMandatory="ENABLE_ASM==true", IsShow="ENABLE_ASM==true", DisplayName="NBM Flow ASM Groups for default VRF (w/wo SPT-Threshold Infinity)", Description="ASM group ranges with prefixes (len:4-32) [example: 239.1.1.0/25], max 20 ranges. Enabling SPT-Threshold Infinity to prevent switchover to source-tree.", Section="Multicast")
struct ASM_GROUP {
  @(IsMandatory=true, Description="NBM Flow ASM Group Subnet")
  ipV4Address GROUP_ADDRESS;
  @(IsMandatory=true, Description="Subnet Mask Length (Min:4, Max:32)")
  integer PREFIX{
    min = 4;
    max = 32;
  };
  @(IsMandatory=true, Description="Enable SPT-Threshold Infinity")
  boolean ENABLE_SPT_THRESHOLD{
    defaultValue = true;
  };
} ASM_GROUP_RANGES[];

@(IsMandatory=true, IsShow="ENABLE_ASM==true", DisplayName="RP Loopback Id", Description="(Min:0, Max:1023)", Section="Multicast")
integer RP_LB_ID{
min=0;
max=1023;
defaultValue=254;
};

@(IsMandatory=true, IsShow="ENABLE_ASM==true && STATIC_UNDERLAY_IP_ALLOC==false", DisplayName="Fabric RP Loopback IP Range", Description="RP Loopback IP Address Range", Section="Multicast")
ipV4AddressWithSubnet RP_IP_RANGE
{
defaultValue=10.254.254.0/24;
};

#Protocols

@(IsMandatory=true, DisplayName="Fabric Routing Protocol Tag", Description="Routing process tag for the fabric", Section="Protocols")
string LINK_STATE_ROUTING_TAG
{
minLength = 1;
maxLength = 20;
defaultValue=1;
};

@(IsMandatory=false, IsInternal=true)
string LINK_STATE_ROUTING_TAG_PREV;

@(IsMandatory=true, IsShow="LINK_STATE_ROUTING==ospf", DisplayName="OSPF Area Id", Description="OSPF Area Id in IP address format", Section="Protocols")
string OSPF_AREA_ID
{
minLength = 1;
maxLength = 15;
defaultValue=0.0.0.0;
};

@(IsMandatory=true, IsShow="LINK_STATE_ROUTING==ospf", DisplayName="Enable OSPF Authentication", Section="Protocols")
boolean OSPF_AUTH_ENABLE{
defaultValue=false;
};

@(IsMandatory=true, IsShow="LINK_STATE_ROUTING==ospf && OSPF_AUTH_ENABLE==true", DisplayName="OSPF Authentication Key ID", Description="(Min:0, Max:255)", Section="Protocols")
integer OSPF_AUTH_KEY_ID
{
min = 0;
max = 255;
defaultValue = 127;
};

@(IsMandatory=true, IsShow="LINK_STATE_ROUTING==ospf && OSPF_AUTH_ENABLE==true", DisplayName="OSPF Authentication Key", Description="3DES Encrypted", Section="Protocols")
string OSPF_AUTH_KEY
{
minLength = 1;
maxLength = 256;
};

@(IsMandatory=true, IsShow="LINK_STATE_ROUTING==is-is", Enum="level-1,level-2", DisplayName="IS-IS Level", Description="Supported IS types: level-1, level-2", Section="Protocols")
string ISIS_LEVEL
{
defaultValue=level-2;
};

@(IsMandatory=true, IsShow="LINK_STATE_ROUTING==is-is", DisplayName="Enable IS-IS Network Point-to-Point", Description="This will enable network point-to-point on fabric interfaces which are numbered", Section="Protocols")
boolean ISIS_P2P_ENABLE
{
defaultValue=true;
};

@(IsMandatory=true, IsShow="LINK_STATE_ROUTING==is-is", DisplayName="Enable IS-IS Authentication", Section="Protocols")
boolean ISIS_AUTH_ENABLE{
defaultValue=false;
};

@(IsMandatory=true, IsShow="LINK_STATE_ROUTING==is-is && ISIS_AUTH_ENABLE==true", DisplayName="IS-IS Authentication Keychain Name", Section="Protocols")
string ISIS_AUTH_KEYCHAIN_NAME
{
minLength = 1;
maxLength = 63;
};

@(IsMandatory=true, IsShow="LINK_STATE_ROUTING==is-is && ISIS_AUTH_ENABLE==true", DisplayName="IS-IS Authentication Key ID", Description="(Min:0, Max:65535)", Section="Protocols")
integer ISIS_AUTH_KEYCHAIN_KEY_ID
{
min = 0;
max = 65535;
defaultValue = 127;
};

@(IsMandatory=true, IsShow="LINK_STATE_ROUTING==is-is && ISIS_AUTH_ENABLE==true", DisplayName="IS-IS Authentication Key", Description="Cisco Type 7 Encrypted", Section="Protocols")
string ISIS_AUTH_KEY
{
minLength = 1;
maxLength = 255;
};

@(IsMandatory=true, DisplayName="Enable PIM Hello Authentication", Section="Protocols")
boolean PIM_HELLO_AUTH_ENABLE
{
defaultValue=false;
};

@(IsMandatory=true, IsShow="PIM_HELLO_AUTH_ENABLE==true", DisplayName="PIM Hello Authentication Key", Description="3DES Encrypted", Section="Protocols")
string PIM_HELLO_AUTH_KEY
{
minLength = 1;
maxLength = 256;
};

#Advanced

@(IsMandatory=true, IsMTU=true, DisplayName="Intra Fabric Interface MTU", Description="(Min:576, Max:9216). Must be an even number", Section="Advanced")
integer FABRIC_MTU
{
min = 576;
max = 9216;
defaultValue=9216;
};

@(IsMandatory=false, IsInternal=true)
integer FABRIC_MTU_PREV
{
min = 576;
max = 9216;
defaultValue=9216;
};

@(IsMandatory=true, IsMTU=true, DisplayName="Layer 2 Host Interface MTU", Description="(Min:1500, Max:9216). Must be an even number", Section="Advanced")
integer L2_HOST_INTF_MTU
{
min = 1500;
max = 9216;
defaultValue=9216;
};

@(IsMandatory=false, IsInternal=true)
integer L2_HOST_INTF_MTU_PREV
{
min = 1500;
max = 9216;
defaultValue=9216;
};

@(IsMandatory=true, Enum="ps-redundant,combined,insrc-redundant", DisplayName="Power Supply Mode", Description="Default power supply mode for the fabric", Section="Advanced")
string POWER_REDUNDANCY_MODE
{
defaultValue=ps-redundant;
};

@(IsMandatory=false, DisplayName="Enable CDP for Bootstrapped Switch", Description="Enable CDP on management interface", Section="Advanced")
boolean CDP_ENABLE
{
defaultValue=false;
};

#@(IsMandatory=false, DisplayName="Enable Tenant DHCP", Section="Advanced")
#boolean ENABLE_TENANT_DHCP
#{
#defaultValue=false;
#};

@(IsMandatory=true, DisplayName="Enable NX-API", Description="Enable HTTPS NX-API", Section="Hidden")
boolean ENABLE_NXAPI
{
defaultValue=true;
};

@(IsMandatory=true, IsShow="ENABLE_NXAPI==true", Enum="management,default", DisplayName="NX-API VRF", Description="VRF used for NX-API communication", Section="Advanced")
string NXAPI_VRF
{
defaultValue=management;
};

@(IsMandatory=false, IsShow="ENABLE_NXAPI==true", DisplayName="NX-API HTTPS Port Number", Section="Hidden")
integer NXAPI_HTTPS_PORT
{
min = 1;
max = 65535;
defaultValue=443;
};

@(IsMandatory=false, IsShow="ENABLE_NXAPI==true", DisplayName="Enable HTTP NX-API", Section="Hidden")
boolean ENABLE_NXAPI_HTTP
{
defaultValue=false;
};

@(IsMandatory=false, IsShow="ENABLE_NXAPI_HTTP==true", DisplayName="NX-API HTTP Port Number", Section="Hidden")
integer NXAPI_HTTP_PORT
{
min = 1;
max = 65535;
defaultValue=80;
};

@(IsMandatory=false, DisplayName="Enable AAA IP Authorization", Description="Enable only, when IP Authorization is enabled in the AAA Server", Section="Advanced")
boolean AAA_REMOTE_IP_ENABLED
{
defaultValue=false;
};

@(IsMandatory=false, DisplayName="Enable NDFC as Trap Host", Description="Configure NDFC as a receiver for SNMP traps", Section="Advanced")
boolean SNMP_SERVER_HOST_TRAP
{
defaultValue=true;
};

@(IsMandatory=false, IsFreezeMode=true, DisplayName="Disable all deployments in this fabric", Section="Hidden")
boolean DEPLOYMENT_FREEZE
{
defaultValue=false;
};

@(IsMandatory=true, Enum="Enable,Disable", IsShow="AAA_REMOTE_IP_ENABLED==false", Description="Enable to clean switch configuration without reload when PreserveConfig=no", DisplayName="Greenfield Cleanup Option", Section="Hidden")
string GRFIELD_DEBUG_FLAG
{
defaultValue=Disable;
};

@(IsMandatory=false, DisplayName="Enable Precision Time Protocol (PTP)", Section="Advanced")
boolean FEATURE_PTP {
defaultValue=false;
};

@(IsMandatory=true, IsShow="FEATURE_PTP==true", DisplayName="PTP Source Loopback Id", Description="(Min:0, Max:1023)", Section="Advanced")
integer PTP_LB_ID
{
min = 0;
max = 1023;
defaultValue=0;
};

@(IsMandatory=true, IsShow="FEATURE_PTP==true", DisplayName="PTP Domain Id", Description="Multiple Independent PTP Clocking Subdomains on a Single Network (Min:0, Max:127)", Section="Advanced")
integer PTP_DOMAIN_ID
{
min = 0;
max = 127;
defaultValue=0;
};

@(IsMandatory=true, IsShow="FEATURE_PTP==true", Enum="IEEE-1588v2,SMPTE-2059-2,AES67-2015", DisplayName="PTP Profile", Description="Enabled on ISL links only", Section="Advanced")
string PTP_PROFILE
{
defaultValue=SMPTE-2059-2;
};

@(IsMandatory=false, IsMultiLineString=true, DisplayName="Leaf Freeform Config", Description="Additional CLIs For All Leafs and Tier2 Leafs As Captured From Show Running Configuration", Section="Advanced")
string EXTRA_CONF_LEAF;

@(IsMandatory=false, IsMultiLineString=true, DisplayName="Spine Freeform Config", Description="Additional CLIs For All Spines As Captured From Show Running Configuration", Section="Advanced")
string EXTRA_CONF_SPINE;

@(IsMandatory=false, IsMultiLineString=true, DisplayName="Intra-fabric Links Additional Config", Description="Additional CLIs For All Intra-Fabric Links", Section="Advanced")
string EXTRA_CONF_INTRA_LINKS;

#Manageability

@(IsMandatory=false, Description="Comma separated list of IP Addresses (v4/v6)", DisplayName="DNS Server IPs", Section="Manageability")
ipAddressList DNS_SERVER_IP_LIST;

@(IsMandatory="DNS_SERVER_IP_LIST!=null", IsShow="DNS_SERVER_IP_LIST!=null", Description="One VRF for all DNS servers or a comma separated list of VRFs, one per DNS server", DisplayName="DNS Server VRFs", Section="Manageability")
string[] DNS_SERVER_VRF {

};

@(IsMandatory=false, Description="Comma separated list of IP Addresses (v4/v6)", DisplayName="NTP Server IPs", Section="Manageability")
ipAddressList NTP_SERVER_IP_LIST;

@(IsMandatory="NTP_SERVER_IP_LIST!=null", IsShow="NTP_SERVER_IP_LIST!=null", Description="One VRF for all NTP servers or a comma separated list of VRFs, one per NTP server", DisplayName="NTP Server VRFs", Section="Manageability")
string[] NTP_SERVER_VRF {

};

@(IsMandatory=false, Description="Comma separated list of IP Addresses (v4/v6)", DisplayName="Syslog Server IPs", Section="Manageability")
ipAddressList SYSLOG_SERVER_IP_LIST;

@(IsMandatory="SYSLOG_SERVER_IP_LIST!=null", IsShow="SYSLOG_SERVER_IP_LIST!=null", Description="Comma separated list of Syslog severity values, one per Syslog server (Min:0, Max:7)", DisplayName="Syslog Server Severity", Section="Manageability")
string[] SYSLOG_SEV {

};

@(IsMandatory="SYSLOG_SERVER_IP_LIST!=null", IsShow="SYSLOG_SERVER_IP_LIST!=null", Description="One VRF for all Syslog servers or a comma separated list of VRFs, one per Syslog server", DisplayName="Syslog Server VRFs", Section="Manageability")
string[] SYSLOG_SERVER_VRF {

};

@(IsMandatory=false, IsMultiLineString=true, DisplayName="AAA Freeform Config", Description="AAA Configurations", Section="Manageability")
string AAA_SERVER_CONF;

@(IsMandatory=false, NoConfigChg=true, IsDhcpFlag=true, Description="Automatic IP Assignment For POAP", DisplayName="Enable Bootstrap", Section="Bootstrap")
boolean BOOTSTRAP_ENABLE{
defaultValue=false;
};

@(IsMandatory=false, NoConfigChg=true, IsShow="BOOTSTRAP_ENABLE==true", Description="Automatic IP Assignment For POAP From Local DHCP Server", DisplayName="Enable Local DHCP Server", Section="Bootstrap")
boolean DHCP_ENABLE{
defaultValue=false;
};

@(IsMandatory=false, NoConfigChg=true, Enum="DHCPv4", IsShow="DHCP_ENABLE==true && BOOTSTRAP_ENABLE==true", DisplayName="DHCP Version", Section="Bootstrap")
string DHCP_IPV6_ENABLE
{
defaultValue=DHCPv4;
};

@(IsMandatory=true, NoConfigChg=true, IsShow="DHCP_ENABLE==true && BOOTSTRAP_ENABLE==true", Description="Start Address For Switch Out-of-Band POAP", DisplayName="DHCP Scope Start Address", Section="Bootstrap")
ipAddress DHCP_START;

@(IsMandatory=true, NoConfigChg=true, IsShow="DHCP_ENABLE==true && BOOTSTRAP_ENABLE==true", Description="End Address For Switch Out-of-Band POAP", DisplayName="DHCP Scope End Address", Section="Bootstrap")
ipAddress DHCP_END;

@(IsMandatory=true, NoConfigChg=true, IsShow="DHCP_ENABLE==true && BOOTSTRAP_ENABLE==true", Description="Default Gateway For Management VRF On The Switch", DisplayName="Switch Mgmt Default Gateway", Section="Bootstrap")
ipAddress MGMT_GW;

@(IsMandatory=true, NoConfigChg=true, IsShow="DHCP_ENABLE==true && BOOTSTRAP_ENABLE==true && DHCP_IPV6_ENABLE==DHCPv4", Description="(Min:8, Max:30)", DisplayName="Switch Mgmt IP Subnet Prefix", Section="Bootstrap")
integer MGMT_PREFIX
{
min = 8;
max = 30;
defaultValue=24;
};

@(IsMandatory=false, NoConfigChg=true, IsShow="DHCP_ENABLE==true && BOOTSTRAP_ENABLE==true && DHCP_IPV6_ENABLE==DHCPv6", Description="(Min:64, Max:126)", DisplayName="Switch Mgmt IPv6 Subnet Prefix", Section="Bootstrap", IsInternal=true)
integer MGMT_V6PREFIX
{
min = 64;
max = 126;
defaultValue=64;
};

@(IsMandatory=false, NoConfigChg=true, IsShow="BOOTSTRAP_ENABLE==true", Description="Include AAA configs from Manageability tab during device bootup", DisplayName="Enable AAA Config", Section="Bootstrap")
boolean ENABLE_AAA{
defaultValue = false;
};

@(IsMandatory=false, IsShow="BOOTSTRAP_ENABLE==true", IsMultiLineString=true, DisplayName="Bootstrap Freeform Config", Description="Additional CLIs required during device bootup/login e.g. AAA/Radius", Section="Bootstrap")
string BOOTSTRAP_CONF;

@(IsMandatory=false, NoConfigChg=true, IsShow="DHCP_ENABLE==true && BOOTSTRAP_ENABLE==true", IsMultiLineString=true, DisplayName="DHCPv4 Multi Subnet Scope",  Description="lines with # prefix are ignored here", Warning="Enter One Subnet Scope per line. <br/> Start_IP, End_IP, Gateway, Prefix <br/> e.g. <br>10.6.0.2, 10.6.0.9, 10.6.0.1, 24 <br>10.7.0.2, 10.7.0.9, 10.7.0.1, 24", Section="Bootstrap")
string BOOTSTRAP_MULTISUBNET
{
defaultValue=#Scope_Start_IP, Scope_End_IP, Scope_Default_Gateway, Scope_Subnet_Prefix;
};


#Hidden

@(IsMandatory=true, IsFabricType=true, DisplayName="Fabric Type", ReadOnly=true, Section="Hidden")
string FABRIC_TYPE
{
defaultValue=Switch_Fabric;
};

@(IsMandatory=false, Section="Hidden")
string EXT_FABRIC_TYPE;

@(IsMandatory=true, IsFabricTechnology=true, ReadOnly=true, Section="Hidden")
string FABRIC_TECHNOLOGY
{
defaultValue=IPFM_Fabric;
};

@(IsMandatory=true, Enum="Multicast", IsReplicationMode=true, Section="Hidden")
string REPLICATION_MODE
{
defaultValue=Multicast;
};

@(IsMandatory=false, Description="Enable Agnet (developmet purpose only)", DisplayName="Enable Agent", Section="Hidden")
boolean ENABLE_AGENT
{
defaultValue=false;
};

@(IsMandatory=false, Description="Interface to connect to Agent", DisplayName="Agent Interface", Enum="eth0,eth1", Section="Hidden")
string AGENT_INTF
{
defaultValue=eth0;
};

@(IsMandatory=false, Enum="Enable,Disable", Description="Dont' use until you are aware about it", DisplayName="!!! Only for brf debugging purpose !!!", Section="Hidden")
string BRFIELD_DEBUG_FLAG
{
defaultValue=Disable;
};

@(IsMandatory=true, DisplayName="Active Migration", Section="Hidden")
boolean ACTIVE_MIGRATION
{
defaultValue=false;
};

@(IsMandatory=true, DisplayName="Template Family", Section="Hidden")
string FF
{
defaultValue=Easy_Fabric_IPFM;
};

@(IsMandatory=false, NoConfigChg=true, IsInternal=true, Section="Bootstrap")
ipV4AddressWithSubnet RP_IP_RANGE_INTERNAL;

@(IsMandatory=false, NoConfigChg=true, IsInternal=true, Section="Bootstrap")
ipAddress DHCP_START_INTERNAL;

@(IsMandatory=false, NoConfigChg=true, IsInternal=true, Section="Bootstrap")
ipAddress DHCP_END_INTERNAL;

@(IsMandatory=false, NoConfigChg=true, IsInternal=true, Section="Bootstrap")
ipAddress MGMT_GW_INTERNAL;

@(IsMandatory=false, NoConfigChg=true, IsInternal=true, Section="Bootstrap")
integer MGMT_PREFIX_INTERNAL;

@(IsMandatory=false, NoConfigChg=true, IsInternal=true, Section="Bootstrap")
string BOOTSTRAP_MULTISUBNET_INTERNAL;

@(IsMandatory=false, NoConfigChg=true, IsInternal=true, Section="Bootstrap")
integer MGMT_V6PREFIX_INTERNAL;

@(IsMandatory=false, NoConfigChg=true, IsInternal=true, Section="Bootstrap")
string DHCP_IPV6_ENABLE_INTERNAL;

@(IsMandatory=true, IsInternal=true)
boolean FEATURE_PTP_INTERNAL
{
defaultValue=false;
};

@(IsMandatory=false, IsInternal=true)
integer SPINE_COUNT
{
defaultValue=0;
};

#All policy templates starts from here.
@(IsMandatory=true, Enum="base_dhcp", Description="DHCP Configuration", DisplayName="base_dhcp", Section="Policy Templates", IsInternal=true)
string abstract_dhcp
{
defaultValue=base_dhcp;
};

@(IsMandatory=true, Enum="int_fabric_loopback_11_1", Description="Primary Loopback Interface Configuration", DisplayName="loopback_interface", Section="Policy Templates", IsInternal=true)
string abstract_loopback_interface
{
defaultValue=int_fabric_loopback_11_1;
};

@(IsMandatory=true, Enum="base_isis_level2", Description="ISIS Network Configuration", DisplayName="base_isis_level2", Section="Policy Templates", IsInternal=true)
string abstract_isis
{
defaultValue=base_isis_level2;
};

@(IsMandatory=true, Enum="base_ospf", Description="OSPF Network Configuration", DisplayName="base_ospf", Section="Policy Templates", IsInternal=true)
string abstract_ospf
{
defaultValue=base_ospf;
};

@(IsMandatory=true, Enum="isis_interface", Description="ISIS Interface Configuration", DisplayName="isis_interface", Section="Policy Templates", IsInternal=true)
string abstract_isis_interface
{
defaultValue=isis_interface;
};

@(IsMandatory=true, Enum="ospf_interface", Description="OSPF Interface Configuration", DisplayName="ospf_interface_11_1", Section="Policy Templates", IsInternal=true)
string abstract_ospf_interface
{
defaultValue=ospf_interface_11_1;
};

@(IsMandatory=true, Enum="pim_interface", Description="PIM Interface Configuration", DisplayName="pim_interface", Section="Policy Templates", IsInternal=true)
string abstract_pim_interface
{
defaultValue=pim_interface;
};

@(IsMandatory=true, Enum= "extra_config_leaf", Description="Add Extra Configuration for Leaf", DisplayName="extra_config_leaf", Section="Policy Templates", IsInternal=true)
string abstract_extra_config_leaf
{
defaultValue=extra_config_leaf;
};

@(IsMandatory=true, Enum= "extra_config_bootstrap", Description="Add Extra Configuration for Bootstrap", DisplayName="extra_config_bootstrap", Section="Policy Templates", IsInternal=true)
string abstract_extra_config_bootstrap
{
defaultValue=extra_config_bootstrap_11_1;
};

@(IsMandatory=true, Enum= "extra_config_spine", Description="Add Extra Configuration for Spine", DisplayName="extra_config_spine", Section="Policy Templates", IsInternal=true)
string abstract_extra_config_spine
{
defaultValue=extra_config_spine;
};

@(IsMandatory=true, Enum="int_ipfm_l3_port", Description="L3 Port Configuration", DisplayName="l3_port", Section="Policy Templates", IsInternal=true)
string abstract_routed_host
{
defaultValue=int_ipfm_l3_port;
};

@(IsMandatory=false, Enum="int_ipfm_l3_port", Description="Default policy for Ethernet interface of spine/leaf/tier2-leaf switches", DisplayName="Ethernet Interface Default Policy", Section="Policy Templates", IsInternal=true)
string INTERFACE_ETHERNET_DEFAULT_POLICY
{
defaultValue=int_ipfm_l3_port;
};

@(IsMandatory=true, Enum="int_ipfm_loopback", DisplayName="Loopback Interface Default Policy", Section="Policy Templates", IsInternal=true)
string INTERFACE_LOOPBACK_DEFAULT_POLICY
{
defaultValue=int_ipfm_loopback;
};

@(IsMandatory=true, Enum="int_ipfm_port_channel_trunk_host", DisplayName="Port Channel Interface Default Policy", Section="Policy Templates", IsInternal=true)
string INTERFACE_PORT_CHANNEL_DEFAULT_POLICY
{
defaultValue=int_ipfm_port_channel_trunk_host;
};

@(IsMandatory=true, Enum="int_ipfm_vlan", DisplayName="VLAN Interface Default Policy", Section="Policy Templates", IsInternal=true)
string INTERFACE_VLAN_DEFAULT_POLICY
{
defaultValue=int_ipfm_vlan;
};

@(IsMandatory=false, IsInternal=true)
string UPGRADE_FROM_VERSION;

##
##template content

from com.cisco.dcbu.vinci.rest.services.jython import PTIWrapper as PTI
from com.cisco.dcbu.vinci.rest.services.jython import Wrapper
from com.cisco.dcbu.vinci.rest.services.jython import WrappersResp
from com.cisco.dcbu.vinci.rest.services.jython import TopologyWrapper
from com.cisco.dcbu.vinci.rest.services.jython import ResourceManagerWrapper as RM
from com.cisco.dcbu.vinci.rest.services.jython import InterfaceManagerWrapper as IM
from com.cisco.dcbu.vinci.rest.services.jython import InterfaceTypeEnum
from com.cisco.dcbu.vinci.rest.services.jython import InventoryWrapper
from com.cisco.dcbu.vinci.rest.services.jython import ImageManagementWrapper
from com.cisco.dcbu.vinci.rest.services.jython import Helper
from com.cisco.dcbu.vinci.rest.services.jython import FabricWrapper
