def isValidOspfAreaIdIPString(ipStr):
    ip = re.findall( r'''^[0-9]+(?:\.[0-9]+){3}$''', ipStr)
    isValid = True
    if len(ip) == 1:
        # convert string to ints
        ipInts = map(int, ip[0].split('.'))
        for ipInt in ipInts:
            if not ((ipInt >= 0) and (ipInt <= 255)):
                isValid = False
                break
    else:
        # not a valid IP address string
        isValid = False
    Wrapper.print("isValidOspfAreaIdIPString: FAB [%s]: OSPF Area Id IP String [%s]  isValid [%r]" % (FABRIC_NAME, ipStr, isValid))
    return isValid

# returns True if change is allowed
def checkFabricMtuSettings(respObj):
    retCode = True

    Wrapper.print("checkFabricMtuSettings: FAB [%s]: Intra Fabric interface MTU [%s] -> [%s]" %
                  (FABRIC_NAME, FABRIC_MTU_PREV, FABRIC_MTU))
    # ensure the MTU value is an even number
    if (int(FABRIC_MTU) % 2) != 0:
        # cannot allow this change
        respObj.addErrorReport("fabricInit", "Intra Fabric interface MTU [%s] must be an even number." % (FABRIC_MTU))
        respObj.setFailureRetCode()
        retCode = False

    Wrapper.print("checkFabricMtuSettings: FAB [%s]: Layer 2 Host interface MTU [%s] -> [%s]" %
                (FABRIC_NAME, L2_HOST_INTF_MTU_PREV, L2_HOST_INTF_MTU))
    # ensure the MTU value is an even number
    if (int(L2_HOST_INTF_MTU) % 2) != 0:
        # cannot allow this change
        respObj.addErrorReport("fabricInit", "Layer 2 Host interface MTU [%s] must be an even number." % (L2_HOST_INTF_MTU))
        respObj.setFailureRetCode()
        retCode = False

    return retCode

# returns True if change is allowed
def checkUnderlayProtocolChange(respObj):
    Wrapper.print("checkUnderlayProtocolChange: FAB [%s]: LINK_STATE_ROUTING [%s]" % (FABRIC_NAME, LINK_STATE_ROUTING))

    topologyDataObj = TopologyData(Util.exe(TopologyWrapper.get(FABRIC_NAME)))
    devices = topologyDataObj.get(TopologyInfoType.SWITCHES)
    devices = filter(None, devices)
    if len(devices) == 0:
        return True

    for deviceSn in devices:
        if LINK_STATE_ROUTING == "is-is":
            ptiList = Util.exe(PTIWrapper.get(deviceSn, "SWITCH", "SWITCH", "UNDERLAY", "base_ospf"))
            ptiListV3 = Util.exe(PTIWrapper.get(deviceSn, "SWITCH", "SWITCH", "UNDERLAY", "base_ospfv3"))
            if ptiList or ptiListV3:
                respObj.addErrorReport("fabricInit",
                    "Cannot change Fabric Routing Protocol to IS-IS with existing OSPF config")
                respObj.setFailureRetCode()
                return False
        elif LINK_STATE_ROUTING == "ospf":
            ptiList = Util.exe(PTIWrapper.get(deviceSn, "SWITCH", "SWITCH", "UNDERLAY", "base_isis_level2"))
            if ptiList:
                respObj.addErrorReport("fabricInit",
                    "Cannot change Fabric Routing Protocol to OSPF with existing IS-IS config")
                respObj.setFailureRetCode()
                return False
    return True

def preUpgrade(dictionaryObj):
    Wrapper.print("==========ACTION: FAB [%s]: Start: preUpgrade" % (FABRIC_NAME))
    respObj = WrappersResp.getRespObj()
    respObj.setSuccessRetCode()
    try:
        if "UPGRADE_FROM" in dictionaryObj:
            Wrapper.print("==========preUpgrade: Fabric Name = %s, keys = %d, UPGRADE_FROM = [%s]" %
                    (FABRIC_NAME, len(dictionaryObj), dictionaryObj["UPGRADE_FROM"]))
        dictionaryObj["FABRIC_NAME"] = FABRIC_NAME
        Util.exe(PTI.executePyTemplateMethod("fabric_upgrade_IPFM", dictionaryObj, "preUpgradeExt"))
    except respObjError as e:
        respObj = e.value
    finally:
        Wrapper.print("==========ACTION: FAB [%s]: Finish: preUpgrade: Success = [%r]" %
                (FABRIC_NAME, respObj.isRetCodeSuccess()))
        return respObj

def preChangeDiscoveryIP(dictionaryObj):
    funcName = sys._getframe(0).f_code.co_name
    Wrapper.print("==========ACTION: FAB [%s]: Start: %s" % (FABRIC_NAME, funcName))
    respObj = WrappersResp.getRespObj()
    respObj.setSuccessRetCode()
    Util.exe(actionAllow())
    try:
        dict = getGlobals(dictionaryObj)
        respObj = PTI.executePyTemplateMethod("fabric_upgrade_11_1", dict, "doPreChangeDiscoveryIP")
    except Exception as e:
        msg = ("Unexpected error during change discovery IP handling")
        if isinstance(e, respObjError):
            respObj.addErrorReport(getFabErrEntity(funcName), msg)
            respObj.setFailureRetCode()
            Util.processRespObj(respObj, e.value)
        else:
            Util.handleException(msg, e, respObj)
    finally:
        Wrapper.print("==========ACTION: FAB [%s]: Finish: %s: Success = [%r]" % (FABRIC_NAME, funcName, respObj.isRetCodeSuccess()))
        return respObj

def fabricInit(dictionaryObj):
    global FABRIC_INTERFACE_TYPE, FEATURE_PTP 
    funcName = sys._getframe(0).f_code.co_name
    Wrapper.print("==========ACTION: FAB [%s]: Start: %s" % (FABRIC_NAME, funcName))
    respObj = WrappersResp.getRespObj()
    respObj.setSuccessRetCode()

    try:
        Util.exe(actionAllow())

        fabricSettings = Util.exe(FabricWrapper.get(FABRIC_NAME)).getNvPairs()
        fabricSettings["FABRIC_TYPE"] = "Switch_Fabric"

        # check the fabric wide links extra config
        errCmd, adjFabricExtraLinkCfg = Util.getAdjustedIntfFreeformConfig(EXTRA_CONF_INTRA_LINKS)
        if errCmd != "":
            respObj.addErrorReport("fabricInit",
                "The Intra fabric link interface freeform extra configuration must not contain the \'interface\' keyword. Please remove the command %s" %
                (errCmd))
            respObj.setFailureRetCode()
            return respObj

        # validate the OSPF Area ID
        if OSPF_AREA_ID != "":
            if not Util.isValidOspfAreaIdIPString(OSPF_AREA_ID):
               respObj.addErrorReport("fabricInit",
                "[%s] - Invalid OSPF Area ID IP String. Please make sure the IP address is valid and contains no white spaces." % OSPF_AREA_ID)
               respObj.setFailureRetCode()
               return respObj

        pmEnable = fabricSettings.get("PM_ENABLE", "false")
        pmEnablePrev = fabricSettings.get("PM_ENABLE_PREV", "false")
        if pmEnable != pmEnablePrev:
            turnOnPM = True if pmEnable == "true" else False
            isFeatEnabled = Util.exe(FabricWrapper.isFeatureEnabled("pm"))
            if isFeatEnabled:
                FabricWrapper.enOrDisFabricPM(FABRIC_NAME, turnOnPM)
            else:
                pmForceUpd = "false" if fabricSettings.get("PM_FORCE_UPD", "true") == "true" else "true"
                FabricWrapper.update(FABRIC_NAME,"PM_FORCE_UPD", pmForceUpd)
                respObj.addErrorReport("fabricInit", "Performance Monitoring feature is not started. "
                                       "Please start Performance Monitoring from Feature Management and retry this operation.")
                respObj.setFailureRetCode()
                return respObj

        nbmPassiveEnable = fabricSettings.get("ENABLE_NBM_PASSIVE", "false")
        nbmPassiveEnablePrev = fabricSettings.get("ENABLE_NBM_PASSIVE_PREV", "false")
        if nbmPassiveEnable != nbmPassiveEnablePrev:
            topologyDataObj = TopologyData(Util.exe(TopologyWrapper.get(FABRIC_NAME)))
            devices = topologyDataObj.get(TopologyInfoType.SWITCHES)
            devices = filter(None, devices)
            if (len(devices) > 0):
                respObj.addErrorReport("fabricInit",
                    "Cannot change default VRF's NBM mode once a device is added to the fabric. "
                    "Fabric needs to be deleted and re-created with the desired mode.")
                respObj.setFailureRetCode()
                return respObj

        # Initialize IsShow dependent variables to their default values if
        # they are set to blank by the backend because the IsShow evaluation is False.
        # Only variables that are identified to show different behavior from 11.3 if
        # they are left blank are initialized.
        if GRFIELD_DEBUG_FLAG == "":
            fabricSettings["GRFIELD_DEBUG_FLAG"] = "Disable"
        if ENABLE_NBM_PASSIVE == "true":
            fabricSettings["ENABLE_ASM"] = "false"
        if OSPF_AUTH_ENABLE == "":
           fabricSettings["OSPF_AUTH_ENABLE"] = "false"
        if ISIS_LEVEL == "":
           fabricSettings["ISIS_LEVEL"] = "level-2"
        if ISIS_AUTH_ENABLE == "":
            fabricSettings["ISIS_AUTH_ENABLE"] = "false"
        if PIM_HELLO_AUTH_ENABLE == "":
            fabricSettings["PIM_HELLO_AUTH_ENABLE"] = "false"
        if ENABLE_NXAPI_HTTP == "":
            fabricSettings["ENABLE_NXAPI_HTTP"] = "false"
        if DHCP_ENABLE == "":
            fabricSettings["DHCP_ENABLE"] = "false"
        if DHCP_ENABLE == "true" and DHCP_IPV6_ENABLE == "":
            fabricSettings["DHCP_IPV6_ENABLE"] = "DHCPv4"
        if ENABLE_AAA == "":
            fabricSettings["ENABLE_AAA"] = "false"
        fabricSettings["PM_ENABLE_PREV"] = pmEnable
        fabricSettings["ENABLE_NBM_PASSIVE_PREV"] = nbmPassiveEnable

        # since the NXAPI port parameters are hidden.. always set to them to their default values
        fabricSettings["NXAPI_HTTPS_PORT"] = "443"
        fabricSettings["NXAPI_HTTP_PORT"] = "80"

        # show the example if DHCP is enabled later
        if DHCP_ENABLE != "true" and BOOTSTRAP_MULTISUBNET == "":
            fabricSettings["BOOTSTRAP_MULTISUBNET"] = "#Scope_Start_IP, Scope_End_IP, Scope_Default_Gateway, Scope_Subnet_Prefix"

        FabricWrapper.update(FABRIC_NAME, fabricSettings)

        if ENABLE_ASM == "true":
            # Verify the size of ASM groups
            mcastRangeLo = Util.IP2Int("224.0.0.0")
            mcastRangeHi = Util.IP2Int("239.255.255.255")
            asmGroups = ast.literal_eval(ASM_GROUP_RANGES)
            for group in asmGroups["ASM_GROUP_RANGES"]:
                if "GROUP_ADDRESS" not in group or "PREFIX" not in group:
                    respObj.addErrorReport("fabricInit", "GROUP_ADDRESS or PREFIX cannot be empty")
                    respObj.setFailureRetCode()
                    return respObj
                groupAddress = group["GROUP_ADDRESS"]
                groupInt = Util.IP2Int(groupAddress)
                if groupInt < mcastRangeLo or groupInt > mcastRangeHi:
                    respObj.addErrorReport("fabricInit",
                                           "Invalid ASM group: %s, Valid range: 224.0.0.0 to 239.255.255.255" % groupAddress)
                    respObj.setFailureRetCode()

            if respObj.isRetCodeFailure():
                return respObj

            groupSize = len(asmGroups["ASM_GROUP_RANGES"])
            if groupSize > 20:
                respObj.addErrorReport("fabricInit",
                                       "Maximum ASM group ranges supported is 20, current size: %d" % groupSize)
                respObj.setFailureRetCode()
                return respObj

        dict = getGlobals()
        dict["GLOBALS_SET"] = False
        processRespObj(respObj, PTIWrapper.executePyTemplateMethod("Easy_Fabric_Extn_IPFM", dict, "sanityCheckLoopbackId"))
        if respObj.isRetCodeFailure():
            return respObj

        if not checkFabricMtuSettings(respObj):
            return respObj

        if not checkUnderlayProtocolChange(respObj):
            return respObj

        # check loopback resource range
        if STATIC_UNDERLAY_IP_ALLOC == "false":
            ip0, mask0 = LOOPBACK0_IP_RANGE.split("/")
            if mask0 == "32":
                errMsg = "Routing Loopback IP Range Mask has to be smaller than 32."
                respObj.addErrorReport("fabricInit", errMsg)
                respObj.setFailureRetCode()
                return respObj

        # dhcp initialization for DHCP IPs provided in bootstrap section.
        dict = getGlobals(dictionaryObj)
        Util.exe(dhcpInit(dict))
        dynamicIPPoolsEnable = True

        # Initialization of resource manager for Underlay Resources.
        if STATIC_UNDERLAY_IP_ALLOC == "false":
            checkIfDuplicatePools(respObj)
            Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, PoolName.SUBNET, PoolType.SUBNET, SUBNET_RANGE, SUBNET_TARGET_MASK))
            Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, "LOOPBACK0_IP_POOL", PoolType.IP, LOOPBACK0_IP_RANGE))
            ip, mask = RP_IP_RANGE.split("/") if RP_IP_RANGE else ("","")
            if mask == "32":
                Util.exe(RM.addOrUpdateEmptyPool(FABRIC_NAME, "RP_IP_POOL", PoolType.IP))
            else:
                Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, "RP_IP_POOL", PoolType.IP, RP_IP_RANGE))
        else:
            # init IP pools to be empty. The IP addresses are expected to be explicitly set in RM offline
            Util.exe(RM.addOrUpdateEmptyPool(FABRIC_NAME, PoolName.SUBNET, PoolType.SUBNET))
            Util.exe(RM.addOrUpdateEmptyPool(FABRIC_NAME, "LOOPBACK0_IP_POOL", PoolType.IP))
            Util.exe(RM.addOrUpdateEmptyPool(FABRIC_NAME, "RP_IP_POOL", PoolType.IP))
        Util.exe(RM.addOrUpdateEmptyPool(FABRIC_NAME, "LOOPBACK_IPV6_POOL", PoolType.IP))

        # Initialization of resource manager for Underlay Resources (port-channel and other IDs).
        Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, "PORT_CHANNEL_ID", "1-4096"))

        # 0,254 reserved for underlay - ipfm, rp loopbacks
        Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, "LOOPBACK_ID", "0-1023"))

        # L3 dot1q and encapsulation dot1q vlan pools for Sub-Interface
        Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, "TOP_DOWN_L3_DOT1Q", "2-4094"))
        #Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, "ENCAP_DOT1Q_VLAN", "2-3967"))
        Util.exe(RM.addOrUpdateEmptyPool(FABRIC_NAME, "ENCAP_DOT1Q_VLAN", PoolType.ID))

        # Validate Manageability tab settings
        Util.exe(PTI.executePyTemplateMethod("fabric_utility_11_1", dict, "validateManageabilityTabSettings"))

        respObj.setSuccessRetCode()
        return respObj
    except respObjError as e:
        respObj = e.value
        return respObj
    finally:
        Wrapper.print("==========ACTION: FAB [%s]: Finish: fabricInit: Success = [%r]" %
                      (FABRIC_NAME, respObj.isRetCodeSuccess()))

def updateDHCPInternal(FABRIC_NAME, DHCP_START, DHCP_END, MGMT_GW, MGMT_PREFIX, MGMT_V6PREFIX, BOOTSTRAP_MULTISUBNET, DHCP_IPV6_ENABLE):
    FabricWrapper.update(FABRIC_NAME, "DHCP_START_INTERNAL", DHCP_START.strip())
    FabricWrapper.update(FABRIC_NAME, "DHCP_END_INTERNAL", DHCP_END.strip())
    FabricWrapper.update(FABRIC_NAME, "MGMT_GW_INTERNAL", MGMT_GW.strip())
    FabricWrapper.update(FABRIC_NAME, "MGMT_PREFIX_INTERNAL",  MGMT_PREFIX.strip())
    FabricWrapper.update(FABRIC_NAME, "MGMT_V6PREFIX_INTERNAL",  MGMT_V6PREFIX.strip())
    FabricWrapper.update(FABRIC_NAME, "BOOTSTRAP_MULTISUBNET_INTERNAL",  BOOTSTRAP_MULTISUBNET.strip())
    FabricWrapper.update(FABRIC_NAME, "DHCP_IPV6_ENABLE_INTERNAL", DHCP_IPV6_ENABLE.strip())

#initialize DHCP scope in dchp.conf for bootstrapped devices for automatic IP assignments
def dhcpInit(dictObj):
    try:
        funcName = sys._getframe(0).f_code.co_name
        respObj = WrappersResp.getRespObj()
        try:
            ffType = FF
        except:
            ffType = ""
            pass
        Wrapper.print("%s(): ffType %s"%(funcName, ffType))
        if ffType:
            fabricName                  = FABRIC_NAME
            dhcpStartIp                 = DHCP_START
            dhcpEndIp                   = DHCP_END
            dhcpMgmtGwIp                = MGMT_GW
            dhcpMultiSubnet             = BOOTSTRAP_MULTISUBNET
            dhcpStartIpInternal         = DHCP_START_INTERNAL
            dhcpEndIpInternal           = DHCP_END_INTERNAL
            dhcpMgmtGwIpInternal        = MGMT_GW_INTERNAL
            dhcpMultiSubnetInternal     = BOOTSTRAP_MULTISUBNET_INTERNAL
            isIPv6                      = DHCP_IPV6_ENABLE
            isIPv6Internal              = DHCP_IPV6_ENABLE_INTERNAL
            dhcpMgmtGwPrefix            = MGMT_PREFIX
            dhcpMgmtGwPrefixInternal    = MGMT_PREFIX_INTERNAL
            dhcpMgmtIPv6GwPrefix        = MGMT_V6PREFIX
            dhcpMgmtIPv6GwPrefixInternal = MGMT_V6PREFIX_INTERNAL
        else:
            fabricName                  = dictObj.get("FABRIC_NAME")
            dhcpStartIp                 = dictObj.get("DHCP_START")
            dhcpEndIp                   = dictObj.get("DHCP_END")
            dhcpMgmtGwIp                = dictObj.get("MGMT_GW")
            dhcpMgmtGwPrefix            = dictObj.get("MGMT_PREFIX")
            dhcpMultiSubnet             = dictObj.get("BOOTSTRAP_MULTISUBNET")
            dhcpStartIpInternal         = dictObj.get("DHCP_START_INTERNAL")
            dhcpEndIpInternal           = dictObj.get("DHCP_END_INTERNAL")
            dhcpMgmtGwIpInternal        = dictObj.get("MGMT_GW_INTERNAL")
            dhcpMultiSubnetInternal     = dictObj.get("BOOTSTRAP_MULTISUBNET_INTERNAL")
            ffType                      = dictObj.get("FF")
            isIPv6                      = dictObj.get("DHCP_IPV6_ENABLE", "DHCPv4")
            isIPv6Internal              = dictObj.get("DHCP_IPV6_ENABLE_INTERNAL","false")
            dhcpMgmtGwPrefix            = dictObj.get("MGMT_PREFIX", "24")
            dhcpMgmtGwPrefixInternal    = dictObj.get("MGMT_PREFIX_INTERNAL", "")
            dhcpMgmtIPv6GwPrefix        = dictObj.get("MGMT_V6PREFIX","64")
            dhcpMgmtIPv6GwPrefixInternal = dictObj.get("MGMT_V6PREFIX_INTERNAL","")

        Wrapper.print("%s(): ffType:[%s] fabricName:[%s], dhcpStartIp:[%s], dhcpEndIp:[%s], dhcpMgmtGwIp:[%s], dhcpMgmtGwPrefix:[%s], "
                      "dhcpMultiSubnet:[%s], dhcpStartIpInternal:[%s], dhcpEndIpInternal:[%s], dhcpMgmtGwIpInternal:[%s], "
                      "dhcpMgmtGwPrefixInternal:[%s], dhcpMultiSubnetInternal:[%s], isV6DHCP:[%s], isIPv6Internal:[%s]"%
                      (funcName, ffType, fabricName, dhcpStartIp, dhcpEndIp, dhcpMgmtGwIp, dhcpMgmtGwPrefix, dhcpMultiSubnet, dhcpMultiSubnet, dhcpEndIpInternal,
                       dhcpMgmtGwIpInternal, dhcpMgmtGwPrefixInternal, dhcpMultiSubnetInternal,isIPv6, isIPv6Internal))

        if Util.exe(FabricWrapper.get(fabricName, "DHCP_ENABLE")) == "true":
            Wrapper.print("===%s(): DHCP Creation start==="%(funcName))
            if ":" in (dhcpStartIp or dhcpEndIp or dhcpMgmtGwIp):
                errorMsg = "Please specify IPv4 address, DHCP IPv6 is not supported."
                respObj.addErrorReport(getFabErrEntity(funcName, fabricName), errorMsg)
                respObj.setFailureRetCode()
                return respObj

            errorMsg = ""
            if not dhcpStartIp or not dhcpEndIp or not dhcpMgmtGwIp or (not dhcpMgmtGwPrefix and not dhcpMgmtIPv6GwPrefix):
                errorMsg = ("Please provide DHCP Start IP, End IP, Management Gateway and Prefix "
                            "when DHCP automatic IP assignment is enabled in bootstrap section")
            else:
                if ((dhcpStartIp.strip()== dhcpStartIpInternal.strip()) and
                    (dhcpEndIp.strip() == dhcpEndIpInternal.strip()) and
                    (dhcpMgmtGwIp.strip() == dhcpMgmtGwIpInternal.strip()) and
                    (dhcpMgmtIPv6GwPrefix.strip() == dhcpMgmtIPv6GwPrefixInternal.strip()) and
                    (dhcpMgmtGwPrefix.strip() == dhcpMgmtGwPrefixInternal.strip()) and
                    (isIPv6.strip() == isIPv6Internal.strip()) and
                    (dhcpMultiSubnet.strip() == dhcpMultiSubnetInternal.strip())):
                    Wrapper.print("===%s(): No change on DHCP==="%(funcName))
                    respObj.setSuccessRetCode()
                    return respObj
                if isIPv6 == "DHCPv6" and isIPv6Internal == "DHCPv4":
                    PTI.executePyTemplateMethod("dhcp_utility", dictObj, "deleteDHCPScope")
                elif (isIPv6 == "DHCPv4" or isIPv6 == "") and isIPv6Internal == "DHCPv6":
                    PTI.executePyTemplateMethod("dhcp_utility", dictObj, "deleteDHCPScopeV6")

                if isIPv6 == "DHCPv6":
                    if "." in dhcpStartIp.strip() or "." in dhcpEndIp.strip() or "." in dhcpMgmtGwIp.strip():
                        errorMsg = ("Please provide IPv6 DHCP Start IP, End IP, Management Gateway and Prefix "
                                    "when IPv6 DHCP automatic IP assignment is enabled in bootstrap section")
                        respObj.addErrorReport(getFabErrEntity(funcName, fabricName), errorMsg)
                        respObj.setFailureRetCode()
                        return respObj

                    Util.exe(PTI.executePyTemplateMethod("dhcp_utility", dictObj, "dhcpScopeV6"))
                else:
                    if ":" in dhcpStartIp.strip() or ":" in dhcpEndIp.strip() or ":" in dhcpMgmtGwIp.strip():
                        errorMsg = ("Please provide IPv4 DHCP Start IP, End IP, Management Gateway and Prefix "
                                    "when IPv6 DHCP automatic IP assignment is not enabled in bootstrap section")
                        respObj.addErrorReport(getFabErrEntity(funcName, fabricName), errorMsg)
                        respObj.setFailureRetCode()
                        return respObj

                    #Validate fabric setting change
                    Util.exe(PTI.executePyTemplateMethod("dhcp_utility", dictObj, "dhcpScope"))
                    topologyDataObj = TopologyData(Util.exe(TopologyWrapper.get(fabricName)))
                    # Add static entries for switches already in the fabric
                    devices = topologyDataObj.get(TopologyInfoType.SWITCHES)  # all devices serial number
                    devices = filter(None, devices)
                    mgmtGwList = []
                    mgmtPrefixList = []

                    if dhcpMultiSubnet.strip():
                        bStrapSnetList = dhcpMultiSubnet.strip().splitlines()
                        allSnetList = filter(lambda x: "#" not in x, bStrapSnetList)
                        allSnetList = list(filter(None, allSnetList))
                        for i in range(len(allSnetList)):
                            singleSnetList = allSnetList[i].split(",")
                            mgmtGwList.append(singleSnetList[2].strip())
                            mgmtPrefixList.append(singleSnetList[3].strip())

                    if dhcpMgmtGwIp and dhcpMgmtGwPrefix:
                        mgmtGwList.append(dhcpMgmtGwIp)
                        mgmtPrefixList.append(dhcpMgmtGwPrefix)

                    for deviceSn in devices:
                        mgmtIp = topologyDataObj.get(TopologyInfoType.MGMT_IP, deviceSn)
                        devModel = topologyDataObj.getSwitchModel(deviceSn)
                        if ":" in mgmtIp or "N7" in devModel:
                            Wrapper.print("%s(): skip mgmt intf with IPV6 or static entry for external fabric [%s]"%(funcName, mgmtIp))
                            continue
                        Wrapper.print("%s():  deviceIP [%s], mgmtGW(s) [%s], mgmtPrefix(es) [%s]" %(funcName, mgmtIp, ",".join(mgmtGwList), ",".join(mgmtPrefixList)))
                        if len(mgmtGwList) == 1:
                            mgmtGw = mgmtGwList[0]
                            mgmtPrefix = mgmtPrefixList[0]
                            Wrapper.print("%s():  device IP [%s], mgmtGW [%s] mgmtPrefix [%s]" %(funcName, mgmtIp,  mgmtGw, mgmtPrefix))
                            #DHCPUtil.dhcpDeviceBlock(DHCPUtil.ADD_BULK_HOSTS, fabricName, deviceSn, mgmtIp, mgmtGw)
                        elif len(mgmtGwList) > 1:
                            for i in range(len(mgmtGwList)):
                                mgmtGw = mgmtGwList[i]
                                mgmtPrefix = mgmtPrefixList[i]
                                nw = mgmtGw + '''/''' + mgmtPrefix
                                Wrapper.print("%s():  device IP [%s], mgmtGW [%s] mgmtPrefix [%s] network [%s]" % (funcName, mgmtIp, mgmtGw , mgmtPrefix, nw))
                                if DHCPUtil.isValidAddrInNw(mgmtIp, nw):
                                    Wrapper.print("%s(): create PTIs with device IP [%s], mgmtGW [%s] mgmtPrefix [%s]" % (funcName, mgmtIp, mgmtGw , mgmtPrefix))
                                    #DHCPUtil.dhcpDeviceBlock(DHCPUtil.ADD_BULK_HOSTS, fabricName, deviceSn, mgmtIp, mgmtGw)
                    DHCPUtil.dhcpDeviceBlock(DHCPUtil.RESTART_DHCP, fabricName)
                updateDHCPInternal(fabricName, dhcpStartIp, dhcpEndIp, dhcpMgmtGwIp, dhcpMgmtGwPrefix, dhcpMgmtIPv6GwPrefix, dhcpMultiSubnet, isIPv6)
            if errorMsg:
                respObj.addErrorReport(getFabErrEntity(funcName, fabricName), errorMsg)
                respObj.setFailureRetCode()
                return respObj
        else:
            Wrapper.print("===%s(): DHCP deletion start==="%(funcName))
            PTI.executePyTemplateMethod("dhcp_utility", dictObj, "deleteDHCPScopeV6")
            PTI.executePyTemplateMethod("dhcp_utility", dictObj, "deleteDHCPScope")
